import React, { useState } from 'react';
import { TopNav } from '../TopNav';
import { Plus, X, CheckCircle2, Clock, XCircle } from 'lucide-react';

const LEAVE_TYPES = ['Annual Leave', 'Sick Leave', 'Unpaid Leave', 'Remote Work'];

const initialRequests = [
  { id: 1, type: 'Annual Leave',  from: '2025-06-20', to: '2025-06-27', days: 6, status: 'Approved', note: 'Summer vacation' },
  { id: 2, type: 'Sick Leave',    from: '2025-05-12', to: '2025-05-13', days: 2, status: 'Approved', note: '' },
  { id: 3, type: 'Remote Work',   from: '2025-06-16', to: '2025-06-16', days: 1, status: 'Pending',  note: 'Doctor appointment' },
  { id: 4, type: 'Annual Leave',  from: '2025-04-01', to: '2025-04-02', days: 2, status: 'Rejected', note: 'Easter weekend' },
];

const statusMeta = {
  Approved: { icon: CheckCircle2, cls: 'bg-emerald-400/10 text-emerald-400' },
  Pending:  { icon: Clock,        cls: 'bg-amber-400/10 text-amber-400'   },
  Rejected: { icon: XCircle,      cls: 'bg-red-400/10 text-red-400'       },
};

export default function LeavePage() {
  const [requests, setRequests] = useState(initialRequests);
  const [showModal, setShowModal] = useState(false);
  const [form, setForm] = useState({ type: LEAVE_TYPES[0], from: '', to: '', note: '' });

  function handleSubmit(e) {
    e.preventDefault();
    if (!form.from || !form.to) return;
    const ms = new Date(form.to) - new Date(form.from);
    const days = Math.max(1, Math.round(ms / (1000 * 60 * 60 * 24)) + 1);
    setRequests((prev) => [
      {
        id: Date.now(),
        type: form.type,
        from: form.from,
        to: form.to,
        days,
        status: 'Pending',
        note: form.note,
      },
      ...prev,
    ]);
    setShowModal(false);
    setForm({ type: LEAVE_TYPES[0], from: '', to: '', note: '' });
  }

  const balance = { annual: 21, taken: 8, remaining: 13 };

  return (
    <div className="flex flex-col min-h-full bg-dash-bg">
      <TopNav title="Leave" />
      <main className="p-6 space-y-6">

        {/* Balance cards */}
        <div className="grid grid-cols-3 gap-4">
          {[
            { label: 'Total entitlement', value: `${balance.annual} days` },
            { label: 'Days taken',        value: `${balance.taken} days`  },
            { label: 'Remaining',         value: `${balance.remaining} days` },
          ].map((k) => (
            <div key={k.label} className="bg-dash-card border border-dash-border rounded-xl p-4 flex flex-col gap-1">
              <span className="text-dash-text-muted" style={{ fontSize: '12px' }}>{k.label}</span>
              <span className="text-dash-text" style={{ fontSize: '24px', fontWeight: 700 }}>{k.value}</span>
            </div>
          ))}
        </div>

        {/* Requests table + action */}
        <div className="bg-dash-card border border-dash-border rounded-xl overflow-hidden">
          <div className="flex items-center justify-between px-5 py-4 border-b border-dash-border">
            <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Leave Requests</h3>
            <button
              onClick={() => setShowModal(true)}
              className="flex items-center gap-1.5 bg-dash-primary text-white px-3 py-1.5 rounded-lg hover:bg-dash-primary/90 transition-colors"
              style={{ fontSize: '13px', fontWeight: 500 }}
            >
              <Plus size={14} />
              New Request
            </button>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-dash-border">
                  {['Type', 'From', 'To', 'Days', 'Status', 'Note'].map((h) => (
                    <th key={h} className="px-5 py-3 text-left text-dash-text-muted" style={{ fontSize: '11px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {requests.map((r) => {
                  const meta = statusMeta[r.status];
                  return (
                    <tr key={r.id} className="border-b border-dash-border last:border-0 hover:bg-dash-sidebar-hover transition-colors">
                      <td className="px-5 py-3 text-dash-text" style={{ fontSize: '13px' }}>{r.type}</td>
                      <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>{r.from}</td>
                      <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>{r.to}</td>
                      <td className="px-5 py-3 text-dash-text" style={{ fontSize: '13px' }}>{r.days}</td>
                      <td className="px-5 py-3">
                        <span className={`flex items-center gap-1 w-fit px-2 py-0.5 rounded-full text-xs font-medium ${meta.cls}`}>
                          <meta.icon size={11} />
                          {r.status}
                        </span>
                      </td>
                      <td className="px-5 py-3 text-dash-text-muted" style={{ fontSize: '13px' }}>{r.note || '—'}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      </main>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm">
          <div className="bg-dash-card border border-dash-border rounded-2xl w-full max-w-md mx-4 shadow-2xl">
            <div className="flex items-center justify-between px-6 py-4 border-b border-dash-border">
              <h3 className="text-dash-text" style={{ fontSize: '15px', fontWeight: 600 }}>New Leave Request</h3>
              <button onClick={() => setShowModal(false)} className="text-dash-text-muted hover:text-dash-text transition-colors">
                <X size={18} />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="px-6 py-5 space-y-4">
              <div>
                <label className="block text-dash-text-muted mb-1.5" style={{ fontSize: '12px', fontWeight: 500 }}>Leave type</label>
                <select
                  value={form.type}
                  onChange={(e) => setForm((f) => ({ ...f, type: e.target.value }))}
                  className="w-full bg-dash-sidebar border border-dash-border rounded-lg px-3 py-2 text-dash-text outline-none focus:border-dash-primary transition-colors"
                  style={{ fontSize: '13px' }}
                >
                  {LEAVE_TYPES.map((t) => <option key={t}>{t}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-dash-text-muted mb-1.5" style={{ fontSize: '12px', fontWeight: 500 }}>From</label>
                  <input type="date" required value={form.from} onChange={(e) => setForm((f) => ({ ...f, from: e.target.value }))}
                    className="w-full bg-dash-sidebar border border-dash-border rounded-lg px-3 py-2 text-dash-text outline-none focus:border-dash-primary transition-colors" style={{ fontSize: '13px' }} />
                </div>
                <div>
                  <label className="block text-dash-text-muted mb-1.5" style={{ fontSize: '12px', fontWeight: 500 }}>To</label>
                  <input type="date" required value={form.to} onChange={(e) => setForm((f) => ({ ...f, to: e.target.value }))}
                    className="w-full bg-dash-sidebar border border-dash-border rounded-lg px-3 py-2 text-dash-text outline-none focus:border-dash-primary transition-colors" style={{ fontSize: '13px' }} />
                </div>
              </div>
              <div>
                <label className="block text-dash-text-muted mb-1.5" style={{ fontSize: '12px', fontWeight: 500 }}>Note (optional)</label>
                <textarea value={form.note} onChange={(e) => setForm((f) => ({ ...f, note: e.target.value }))}
                  rows={2} placeholder="Reason for leave..."
                  className="w-full bg-dash-sidebar border border-dash-border rounded-lg px-3 py-2 text-dash-text placeholder-dash-text-muted outline-none focus:border-dash-primary transition-colors resize-none"
                  style={{ fontSize: '13px' }} />
              </div>
              <div className="flex gap-3 pt-1">
                <button type="button" onClick={() => setShowModal(false)}
                  className="flex-1 py-2 rounded-lg border border-dash-border text-dash-text-secondary hover:bg-dash-sidebar-hover transition-colors" style={{ fontSize: '13px' }}>
                  Cancel
                </button>
                <button type="submit"
                  className="flex-1 py-2 rounded-lg bg-dash-primary text-white hover:bg-dash-primary/90 transition-colors" style={{ fontSize: '13px', fontWeight: 500 }}>
                  Submit Request
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
